code = """# Check the distribution of histological types among alive bladder cancer patients
import json

# Load bladder clinical data
bladder_result = locals()['var_functions.query_db:66']
if isinstance(bladder_result, str):
    with open(bladder_result, 'r') as f:
        bladder_clinical = json.load(f)
else:
    bladder_clinical = bladder_result

# Count histological types
histology_counts = {}
for patient in bladder_clinical:
    hist_type = patient.get('histological_type')
    if not hist_type or hist_type == "None":
        hist_type = "Unspecified"
    
    histology_counts[hist_type] = histology_counts.get(hist_type, 0) + 1

# Sort by count descending
sorted_histologies = sorted(histology_counts.items(), key=lambda x: x[1], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'total_patients': len(bladder_clinical),
    'histology_distribution': sorted_histologies,
    'unique_histologies': len(sorted_histologies)
}, indent=2))"""

